1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_PRICE = 60;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	function calculateItemPremium(item: any): number {
14	  const base = BASE_PREMIUMS[item.type];
15	  let premium = base;
16	  if (item.cursed) {
17	    premium += base * 0.5;
18	  }
19	  if (item.enchantment >= 5) {
20	    premium += base * 0.3;
21	  }
22	  return premium;
23	}
